var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 가변 심도 좌표\\n<color=#ff3636>필하모닉 홀</color>","JPN":"裏世界可変深度座標\\n<color=#ff3636>フィルハーモニーホール</color>","ENG":"Counterside Variable Depth Coordinates\\n<color=#ff3636>Philharmonic Hall</color>","TWN":"異界可變深度座標\\n<color=#ff3636>管弦樂廳</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"구 관리국 야크샤 전대, 카르데나스 전대.\\n강습 작전 수행 중.\\n작전명 <color=#ffd34c>트러블 슈팅</color>","JPN":"旧管理局ヤクシャー戦隊、カルデナス戦隊。\\n強襲作戦遂行中。\\n作戦名<color=#ffd34c>トラブルシューティング</color>","ENG":"Old Administration Yaksha Division, Cardenas Division.\\nConducting an Assault Operation.\\nOperation Name <color=#ffd34c>Troubleshooting</color>","TWN":"舊管理局 阿克夏戰隊、卡特納斯戰隊\\n執行強襲作戰中。\\n作戰名稱 <color=#ffd34c>故障排除</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"싫어……! 내 머릿속을 헤집지 마!! 싫어어어어!!","JPN":"やめろ……！　頭ん中を掻きまわすな！！　やめろぉぉぉ！！","ENG":"No...! Get out of my head!! Stop!!","TWN":"走開……！滾出我的腦袋！！討厭！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"멈춰!! 아군이다! 능력을 사용하지 마!","JPN":"やめろ！！　味方だ！　能力を使うな！","ENG":"Stop!! We’re allies! Don’t use your powers!","TWN":"住手！！是我方人員！不要使用能力！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"틀렸습니다! 이미 제정신이 아니에요! 사살해야 합니다!!","JPN":"だめです！　正気を失っています！　殺さなければ！！","ENG":"Too late! He’s already lost his mind! We must shoot!","TWN":"不行！他現在已經神智不清！必須立刻擊斃！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"내 배 안에 벌레가 들어 있어…… 내, 내 배 안에서 그게 꿈틀거리다가……!","JPN":"腹の中に虫が入っている……ぼ、僕の腹の中でアレがうごめいて……！","ENG":"There’s a bug in my stomach... It’s, it’s wiggling around in my stomach...!","TWN":"我肚子裡有蟲……蟲在我的肚子裡蠕動……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"정신 차려, 이 멍청아! 그건 놈들이 덮어 씌운 기억이야! 속지 마!!","JPN":"しっかりしろ、バカ野郎！　それはやつらが上書きした記憶だ！　騙されるな！！","ENG":"Pull yourself together, idiot! That’s just a memory they’ve planted into your brain! Don’t be fooled!","TWN":"傻瓜，你清醒一點！這是那些傢伙植入的記憶！不可以上當！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 진정제 주사해! 저 놈 자기 손으로 배 가르는 꼴 보고 싶어?!","JPN":"早く鎮静剤を打て！　あいつが自分で腹を切るところを見たいのか！？","ENG":"Somebody, sedate him! Do you want to see him rip his stomach apart with his own hands?!","TWN":"立刻給他打鎮定劑！還是你想看他把自己的肚皮挖破？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지휘부에! 멘탈 프린팅을 촉발하는 파동이 검출되었습니다!</color>","JPN":"<color=#ffd34c>司令部へ！　メンタル・プリンティングを起こす波動が検出されました！</color>","ENG":"<color=#ffd34c>Command! A wave triggering Mental Printing has been detected!</color>","TWN":"<color=#ffd34c>指揮部感應到觸發智力複印的波動！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>첩보가 틀렸습니다! 마에스트로가 아직 이곳에……!</color>","JPN":"<color=#ffd34c>諜報が間違っていました！　マエストロがまだここに……！</color>","ENG":"<color=#ffd34c>Our intel was wrong! Maestra is still here...!</color>","TWN":"<color=#ffd34c>情報有誤！指揮家尚未……！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국 놈들은 모두 죽여 버려! 안 돼, 쏘지 마! 죽여 버려! 함장님! 사, 살려……!","JPN":"管理局のやつらは全員死んじまえ！　やめろ、撃つな！　殺せ！　艦長！　た、助け……！","ENG":"Kill everyone from the Administration! Wait, don’t shoot! DIE! Leader! Sa-Save M...!","TWN":"把管理局的傢伙全都殺光！不可以，別開槍！殺光！艦長！救我……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"여기는……. 카르데나스 부전대장, 몽타뉴…….","JPN":"こちら……カルデナス副戦隊長、モンターニュ……","ENG":"This is... Cardenas Deputy Commander Montagne...","TWN":"這裡是……卡特納斯副戰隊長 蒙塔妮……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"현재 아군의 70% 가량이 전투불능 상태…… 작전은 실패다…….","JPN":"現在、味方の70％程度が戦闘不能……作戦は失敗だ……","ENG":"Currently, 70% of our allies are incapacitated... The operation is a failure...","TWN":"目前我方人員中，有70%已經失去作戰能力……作戰失敗……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"차원 도약이 차단되어 생존자들도 퇴각할 수가 없다! 너무 늦기 전에 어서 원군을……!","JPN":"次元跳躍が遮断され、生き残りも退却できない！　遅れる前に早く援軍を……！","ENG":"Dimension jump is being blocked, the survivors can't retreat! Quick, before it's too late—","TWN":"目前次元跳躍關閉中，以至於人員無法撤退！請盡快派遣援軍……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"커윽……!","JPN":"くうっ……！","ENG":"Kagh...!","TWN":"呃……！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어머나. 여기 아직 정신 멀쩡한 인간이 남아 있었네.","JPN":"あら。まだここにまともな人間が残っているとは。","ENG":"Oops. Looks like there's someone still conscious here.","TWN":"哇喔，沒想到還有人是神智清楚的呢～"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"예쁜 소리를 내 줄 악기가 하나 더 늘어서 기쁘시겠어요, 최고 지휘자님.","JPN":"美しい音を出してくれる楽器がもう一つ増えてよかったですね、マエストロ。","ENG":"I guess you'll be happy to add another beautiful instrument to your collection, Maestra Nequitia.","TWN":"現在又多一個可以彈奏出美妙音樂的樂器，您應該很開心吧，首席指揮家？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"악기를 편성하는 것은 제 권한이랍니다, 셰나.","JPN":"楽器の編成は私の権限です、シェナ。","ENG":"Organizing the instruments is my jurisdiction, Shena.","TWN":"世娜，樂器的安排是由我來決定的。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"월권으로 여겨질 수 있는 발언은 조심하시는 편이 좋아요.","JPN":"越権としてみなされるような発言には注意した方がいいですよ。","ENG":"Be careful of what you say. You would not want to overstep your authority.","TWN":"你的發言有越權的疑慮，還請慎言。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이거 실례. 불손한 발언으로 최고 지휘자님의 심기를 거슬렀네요.","JPN":"これは失礼。不遜な発言でマエストロの機嫌を損ねてしまいました。","ENG":"Sorry. Looks like my words annoyed the Chief Conductor.","TWN":"真是抱歉，因為我輕率的發言，惹得首席指揮家不開心！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"최고 지휘자……?","JPN":"マエストロ……？","ENG":"Chief Conductor...?","TWN":"首席指揮家……？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그렇다면 네가…… 네퀴티아……?","JPN":"ってことは、お前が……ネキティア……？","ENG":"If so, you must be... Nequitia...?","TWN":"所以你是…… 莉奎蒂亞……？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"마에스트로라고 불러 주셔도 됩니다. 몽타뉴 부전대장.","JPN":"マエストロとお呼びください。モンターニュ副戦隊長。","ENG":"You may call me Maestra, Deputy Commander Montagne.","TWN":"請稱呼我為指揮家就好，蒙塔妮副戰隊長。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"제가 준비한 연주는 어떠셨는지요.","JPN":"私が用意した演奏はいかがでしたか？","ENG":"What did you think of the performance I prepared?","TWN":"還喜歡我精心預備的演奏嗎？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"관리국의 정예들께서 오신다기에 각별히 공을 들였습니다만.","JPN":"管理局の精鋭がお越しになると聞きましたので、特別に心を配りました。","ENG":"I put a lot of effort into it since the Administration's elites are coming.","TWN":"因為觀眾是管理局的精銳，我特別格外用心預備呢。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"이…… 이, 괴물……!","JPN":"こ……この、化け物……！","ENG":"You... You, monster...!","TWN":"你……你這怪物……！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"괴물이라니 너무 따분한 표현이네. 참신함이라고는 이슬만큼도 없어.","JPN":"化け物だなんて、退屈すぎる表現だわ。新しさはこれっぽちもないわね。","ENG":"Monster? How boring. Can't you come up with something more original?","TWN":"怪物這個說法還真是毫無新意。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그래요. 상투적인 소리를 내는 악기는 제 악단에 편성하고 싶지 않군요.","JPN":"そうですね。ありふれた音を出す楽器は私の楽団に入れたくありません。","ENG":"Indeed. I wouldn't want such a dull instrument to be a part of my Orchestra.","TWN":"沒錯，我可不希望我的樂團裡，有這種老掉牙的聲音。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"그렇다면 지휘자님, 저 인간은 제게 주시겠어요?","JPN":"マエストロ、それならあの人間は私にくださいませんか？","ENG":"If that's the case, how about giving her to me, Maestra Nequitia?","TWN":"那請問指揮家，可以把她交給我嗎？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"흐음. 납득할 수 있는 사유라면 허락해 드리죠, 카르멘.","JPN":"ふうん。納得できる理由があれば許してあげますよ、カルメン。","ENG":"Hmm. Well, if you provide a good enough reason, I will allow it, Carmen.","TWN":"嗯，如果你有合理的理由，那我自然沒有不答應的道理，卡門。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우후훗. 상처 입은 짐승일수록 자기를 돌봐 준 사람에게 호감을 품는다더라고요.","JPN":"うふふっ。怪我を負った獣は面倒を見てくれた人に好感を抱くらしいです。","ENG":"Fuu fuu... The more wounded an animal is, the more it adores its owner.","TWN":"呵呵呵，人家不是說動物都會對救命恩人報恩嗎？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"정성껏 길러서 번식을 시키면 실험체를 구하는 수고도 줄지 않을까요?","JPN":"大事に育てて繁殖させれば、実験体を探す手間も省けるのではないでしょうか？","ENG":"I'll do my best to raise her and have her breed. Then, we would save the effort to seek the test subject?","TWN":"只要好好飼養，再讓她繁殖，就可以不用那麼辛苦找實驗體吧？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"또 그 얘기네. 병아리 한 마리도 제대로 기를 줄 모르는 주제에.","JPN":"またその話ね。ひよこ一匹もまともに育てられないくせに。","ENG":"This again? You couldn't even raise a chick properly.","TWN":"又來！明明連隻小雞都沒養過！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"네놈들은……","JPN":"お前らは……","ENG":"You bastards...","TWN":"你們……"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"네놈들은……! 역시 이 세상에 있어선 안 될 괴물들이야!!","JPN":"お前らは……！　やはりこの世界にいてはならない化け物だ！！","ENG":"You bastards...! Monsters like you shouldn't be allowed to exist in this world!!","TWN":"你們這些傢伙……！果然是不該存在這世界上的怪物！！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"큭……?!","JPN":"くっ……！？","ENG":"Ugh...?!","TWN":"唔……？！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그 공격이 당신의 목숨을 건 마지막 발악이었군요. 목소리에 절박함이 담겨 있었어요.","JPN":"その攻撃があなたの命をかけた最後の悪あがきだったようですね。声に焦りがこもっていました。","ENG":"That appears to be the last attack you will be able to withstand. Your voice sounded quite desperate.","TWN":"剛才的攻擊，是你賭上性命的最後掙扎吧？從你的聲音裡可以聽出急迫感。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"닥…… 쳐……! 네놈 단원들이 방해하지만 않았어도……!","JPN":"うる……さい……！　お前の団員が邪魔さえしなければ……！","ENG":"Shut... up...! If it wasn't for your members, I would have...!","TWN":"你……閉嘴……！要不是你的人礙事……！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"네. 스스로 방패가 되다니 실로 갸륵한 충심이지요.","JPN":"はい。自ら盾になるとは、実に健気な忠誠心ですね。","ENG":"Indeed. How commendable to use yourself as a shield.","TWN":"竟然自願當人肉盾牌，真是忠心耿耿呢。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"하지만 이렇게 실패해서야, 당신에게 퇴각을 지시한 전대장에게 면목이 없지 않나요?","JPN":"ですが、このように失敗しては、あなたに退却の命令を出した戦隊長に合わせる顔がないのではありませんか？","ENG":"However, failing in such manner, isn't it a shame about what happened to your Commander who ordered you to retreat?","TWN":"不過結果是失敗作收，這樣豈不是愧對叫你撤退的戰隊長嗎？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……뭐?","JPN":"……なん……だと？","ENG":"...What did you say?","TWN":"……什麼？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"너……. 전대장님을……. 우, 우리 오빠를 어떻게 한 거야……?","JPN":"お前……戦隊長に……に、兄さんに何をしたんだ……？","ENG":"You... Commander... Wha, what have you done to my brother...?","TWN":"你……你把戰隊長……你把我哥怎麼樣了……？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"용맹하게 저항하시기에 몇 개의 인격을 이식할 수 있는지 시험해 봤습니다.","JPN":"勇ましく抵抗されたので、いくつの人格を移植できるか試してみました。","ENG":"I performed an experiment to see how many personality transplants his brain could withstand.","TWN":"因為他很英勇抵抗，所以我就想說來實驗一下，看他可以移植幾個人格。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"스물한 명째까지 버티시다가 극단적인 선택을 하시더군요. 실로 전대장다웠어요.","JPN":"21人目まで耐え続け、自害されましたね。実に戦隊長らしかったです。","ENG":"He eventually decided to commit suicide all after holding out to the 21st personality. Ah, was he quite the Commander.","TWN":"他撐到第21個後，便採取極端的手段，真不愧是戰隊長。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아, 아냐…….","JPN":"ち、違う……","ENG":"Ah, no...","TWN":"不，不會的……"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"사기를 잃은 장병들에게 보여 주기엔…… 다소 부적절한 최후였답니다.","JPN":"士気を失っている兵士たちに見せるには……少々不適切な最期でした。","ENG":"To present it to the soldiers with no morale... It was, shall we say, a rather indecent death.","TWN":"他最後的下場……確實不太適合讓士氣低落的隊員看到。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아니야……!!","JPN":"違う……！！","ENG":"That can't be...!!","TWN":"不會的……！！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"대소변도 못 가리고 돼지 같은 울음소리를 내면서 기어다니는 추태는…….","JPN":"大小便を垂れ流して、豚のように鳴きながら這いまわる醜態といったら……","ENG":"Not even being able to go to the bathroom on his own, crawling around on the floor snorting like a pig. Such indecent behavior...","TWN":"大小便無法自理，發出像豬一樣的笑聲，一邊在地上爬……"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아냐!! 아니라고!! 아니야!! 아니야아아아아아아!!","JPN":"いや！！　違う！！　違うんだ！！　いやああああああ！！","ENG":"No!! That can't be true!! No way!! No, no, no!!","TWN":"閉嘴！！我不相信！！不會的！！！"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"불쌍해라……. 가족이 죽은 걸 이해 못하나 봐.","JPN":"かわいそうに……家族の死を受け入れられないみたい。","ENG":"Oh, you poor thing... Looks like you can't handle the death of a family member.","TWN":"好可憐喔……她好像無法承受失去家人的痛。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그래도 입마개는 채우고 키워야겠네. 우는 소리가 시끄러우면 주변에 폐가 되니까.","JPN":"でも口輪はつけて飼わないと。鳴き声がうるさいと周りの迷惑になるから。","ENG":"Well, I guess I will have to put a muzzle on you and train you properly. Your cries would be so annoying to the people around you.","TWN":"不過還是必須幫她戴口罩才行，要不然哭聲會打擾到別人。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄? 연주에 방해될 것 같은데 그냥 죽여 버리는 게 어떨까요, 최고 지휘자님?","JPN":"さあ？　演奏の邪魔になると思いますが殺したらどうですか、マエストロ？","ENG":"Looks like she will mess with the performance. Why not just kill her, Maestra Nequitia?","TWN":"有需要嗎？她會干擾到演奏吧？我建議不如直接滅口，不知首席指揮家意下如何？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"……흐음.","JPN":"……ふうん。","ENG":"Hmm...","TWN":"……嗯嗯。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"셰나, 카르멘. 몸가짐을 바로하세요. 귀빈이 오신 모양이군요.","JPN":"シェナ、カルメン。身なりを整えてください。貴賓がいらしたようです。","ENG":"Shena, Carmen. Straighten up. The VIPs are coming.","TWN":"世娜、卡門，請注意你們的儀態，似乎有貴賓來訪。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"귀빈? 지금 관리국이 동원할 수 있는 전대는 없을 텐데요?","JPN":"貴賓？　今管理局が動かせる戦隊はないはずですが？","ENG":"VIPs? I thought there wasn't a Division the Administration could mobilize right now?","TWN":"貴賓？現在管理局應該沒有可動員的戰隊吧？"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"당신은 아직 갈길이 멀어요, 셰나. 그렇기에 귀빈이라는 겁니다.","JPN":"あなたはまだ先が遠いですね、シェナ。だからこそ貴賓なのですよ。","ENG":"You still have a long way to go, Shena. That’s why they're called VIPs.","TWN":"世娜，看來你還有很長的路要走，所以我才說是貴賓的嘛。"},"stage":{"bg":"HARMONY_05","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"방금 보인 검…… 설마?","JPN":"今見えた剣は……まさか？","ENG":"What was the sword I just saw… Could it be?","TWN":"剛剛看到的劍……難道是？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"몽타뉴 부전대장, 무사한가.","JPN":"モンターニュ副戦隊長、無事か？","ENG":"Deputy Commander Montagne, are you unharmed?","TWN":"蒙塔妮副戰隊長，你沒事吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"페, 펜릴 전대장님……! 오빠가, 저희, 오빠가……!","JPN":"フェ、フェンリル戦隊長……！　兄さんが、私の、兄さんが……！","ENG":"Fen..., Fenrir Division Commander...! My brother... My brother...!","TWN":"芬…芬里爾戰隊長……！我哥…我哥他……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……시드도 당해 버렸나. 더 서두르지 못해서 미안하다.","JPN":"……シドもやられてしまったのか。遅くなって悪かった。","ENG":"I see... Even Sid didn’t make it. My apologies for not arriving sooner.","TWN":"……錫德也遇害了嗎？很抱歉，我們來晚了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아차. 고철 마왕님네 사도가 예상보다 오래 못 버텼나 보네.","JPN":"あーあ。食いしん坊魔王の使徒が思ったより長く持たなかったみたいね。","ENG":"Uh-oh. Looks like the Apostle of the junk-metal Demon Lord didn't last as long as expected.","TWN":"哎呀～沒想到貪吃魔王的使徒也就那點能耐。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이수연, 스승님과 함께 멋지게 등장!!","JPN":"カナミ・キズナ、師匠と共に派手に参上！！","ENG":"Lee Sooyeon, alongside her Master, makes her grand entrance!!","TWN":"李秀妍和師父一起華麗登場！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"웃……! 왈가닥 씨까지 따라왔나?","JPN":"うっ……！　おてんばさんまでついてきたの？","ENG":"Hgh...! That tomboy came along too?","TWN":"噗……！這瘋丫頭也跟來啦？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연아! 함부로 접근하지 마! 상대는 보통 그림자들과 달라!","JPN":"キズナ！　むやみに近づくな！　相手は普通のシャドウとは違う！","ENG":"Sooyeon, watch out! Don’t get too close. These are no ordinary Shadows!","TWN":"秀妍！你不要輕舉妄動！對方可不是普通的暗影！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"에에잇! 그러면 스승님 혼자 싸우게 두라는 거야?!","JPN":"ええいっ！　それじゃ師匠一人で戦わせろっていうの！？","ENG":"Yeeeight! You can’t expect the Master to fight alone?!","TWN":"喂喂喂！你這是要讓師父孤軍奮戰的意思嗎？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"이렇게 직접 대면하는 건 오랜만이군요, 힐데님.","JPN":"こうして直接お会いするのは久しぶりですね、ヒルデ様。","ENG":"It has been a long time since we have been face to face like this, hasn’t it, Hilde?","TWN":"別來無恙，希爾德。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_SHADOW_HYPER_ATTACK"},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"아니, 지금은 펜릴 전대장님이라고 불러드려야 할까요?","JPN":"いいえ、今はフェンリル戦隊長とでも呼ぶべきでしょうか？","ENG":"Wait, isn’t it Fenrir Division Commander now?","TWN":"不對，現在應該要稱呼你為芬里爾戰隊長是嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……아군이 함정에 걸렸다더군. 밀정이라도 심어 둔 건가.","JPN":"……味方が罠にはまったらしい。密偵でも送っておいたのか？","ENG":"...Our allies appear to be caught in a trap. Have you planted a secret agent?","TWN":"……聽說我們的人掉入陷阱，是你安排的臥底嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"후훗. 글쎄요. 저와 같이 세계의 진실에 다다르지 못한 자에게는 그에 걸맞은 방식이 있는 법이죠.","JPN":"ふふっ。どうでしょう。私のような世界の真実に辿りつけなかった者にはそれなりのやり方があるものです。","ENG":"Fuu fuu... Well... Those like me who haven’t reached the truth of the world have their own methods.","TWN":"呵呵～這個嘛，像我這種被世界淘汰的人，自有我的方法。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"관리국의 사상에 반대하는 이들이 비단 외부에만 존재하는 것은 아니랍니다.","JPN":"管理局の思想に反対する者は外にだけ存在するわけではありません。","ENG":"It is not only those outside the Administration that oppose its ideals.","TWN":"反對管理局思想的人，可不只有外面的人。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"메이즈 전대와 카멜롯 전대에 전파한다!","JPN":"メイズ戦隊とキャメロット戦隊に伝える！","ENG":"Attention, Maze Division and Camelot Division!","TWN":"傳下去給梅茲戰隊和卡梅羅戰隊！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"적은 제 5종 침식체, 마에스트로 네퀴티아!","JPN":"敵は第5種侵食体、マエストロ・ネキティア！","ENG":"The enemy is Category 5 C.O., Maestra Nequitia!","TWN":"敵人是5類侵蝕體，指揮家 莉奎蒂亞！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"백병전은 펜릴 전대가 전담한다! 화력 투사로 지원하도록!","JPN":"白兵戦はフェンリル戦隊が引き受ける！　火力投射で援護するように！","ENG":"Fenrir Division will carry out close combat! Support with additional firepower!","TWN":"芬里爾戰隊負責白刃戰！請支援火力！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};